1. 修改`lib/stream/xlsx/worksheet-writer.js`
   Modify `lib/stream/xlsx/worksheet-writer.js`

```js
+ const Image = require('../../doc/image');
+ const DrawingXform = require('../../xlsx/xform/sheet/drawing-xform');

const xform = {
+  drawing: new DrawingXform(),
};


class WorksheetWriter {
    commit(){
        this._writeBackground();
+       this._writeDrawing();
        this._writeHeaderFooter();
    }

+   addImage(imageId, range) {
        const model = {
        type: 'image',
        imageId,
        range,
        };
        this._media.push(new Image(this, model));
    }

+   getImages() {
        return this._media.filter(m => m.type === 'image');
    }

+   _writeDrawing() {
    const images = this.getImages();
    if (images.length > 0) {
      // Create drawing object if we have images
      if (!this._drawing) {
        // Initialize workbook drawings count if not exists
        if (!this._workbook.drawingsCount) {
          this._workbook.drawingsCount = 0;
        }

        const drawingName = `drawing${++this._workbook.drawingsCount}`;

        const drawingId = this._sheetRelsWriter.addMedia({
          Target: `../drawings/${drawingName}.xml`,
          Type: 'http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing',
        });

        this._drawing = {
          rId: drawingId,
          name: drawingName,
          anchors: [],
          rels: [],
        };

        // Add drawing to workbook's drawings collection
        if (this._workbook.drawings) {
          this._workbook.drawings.push(this._drawing);
        } else {
          this._workbook.drawings = [this._drawing];
        }
      }

      // Process each image and add to drawing anchors
      images.forEach(imageWrapper => {
        const medium = imageWrapper.model;
        const bookImage = this._workbook.getImage(medium.imageId);

        // Add relationship for the image
        const rIdImage = `rId${this._drawing.rels.length + 1}`;
        this._drawing.rels.push({
          Id: rIdImage,
          Type: 'http://schemas.openxmlformats.org/officeDocument/2006/relationships/image',
          Target: `../media/${bookImage.name}`,
        });

        // Create anchor structure that matches what the drawing xforms expect
        // The imageWrapper.range contains properly constructed Anchor objects
        const anchor = {
          picture: {
            rId: rIdImage,
          },
          range: imageWrapper.range, // This has the proper tl/br Anchor structure
          // Don't set anchorType manually - let the DrawingXform.prepare() determine it
        };

        // Handle hyperlinks if present
        if (medium.hyperlinks && medium.hyperlinks.hyperlink) {
          const rIdHyperLink = `rId${this._drawing.rels.length + 1}`;
          anchor.picture.hyperlinks = {
            tooltip: medium.hyperlinks.tooltip,
            rId: rIdHyperLink,
          };
          this._drawing.rels.push({
            Id: rIdHyperLink,
            Type: RelType.Hyperlink,
            Target: medium.hyperlinks.hyperlink,
            TargetMode: 'External',
          });
        }

        this._drawing.anchors.push(anchor);
      });

      // Write drawing reference to worksheet
      this.stream.write(xform.drawing.toXml({rId: this._drawing.rId}));
    }
  }
}
```


